import React, { useRef, useState } from 'react'
import { Canvas, useFrame, useLoader } from '@react-three/fiber'
import { TextureLoader } from 'three'
import { OrbitControls, Text, Float } from '@react-three/drei'

const EidCube = () => {
  const meshRef = useRef()
  const [hovered, setHover] = useState(false)
  const [clicked, setClick] = useState(false)

  // Replace these URLs with your specific Eid images (Crescent, Lanterns, Mosque, etc.)
  const textures = useLoader(TextureLoader, [
    'https://picsum.photos/id/10/400/400', // Side 1
    'https://picsum.photos/id/20/400/400', // Side 2
    'https://picsum.photos/id/30/400/400', // Side 3
    'https://picsum.photos/id/40/400/400', // Side 4
    'https://picsum.photos/id/50/400/400', // Side 5
    'https://picsum.photos/id/60/400/400', // Side 6
  ])

  // Rotate the cube automatically
  useFrame((state, delta) => {
    meshRef.current.rotation.x += delta * 0.5
    meshRef.current.rotation.y += delta * 0.2

    // Pulse effect when clicked
    if (clicked) {
      meshRef.current.scale.lerp({ x: 1.5, y: 1.5, z: 1.5 }, 0.1)
      setTimeout(() => setClick(false), 1000) 
    } else {
      meshRef.current.scale.lerp({ x: 1, y: 1, z: 1 }, 0.1)
    }
  })

  return (
    <mesh
      ref={meshRef}
      onClick={() => setClick(true)}
      onPointerOver={() => setHover(true)}
      onPointerOut={() => setHover(false)}
    >
      <boxGeometry args={[1.5, 1.5, 1.5]} />
      {textures.map((texture, idx) => (
        <meshStandardMaterial key={idx} attach={`material-${idx}`} map={texture} />
      ))}
    </mesh>
  )
}

export default function App() {
  return (
    <div style={{ width: '100vw', height: '100vh', background: '#0a192f' }}>
      <Canvas camera={{ position: [0, 0, 5] }}>
        <ambientLight intensity={0.5} />
        <pointLight position={[10, 10, 10]} />

        <Float speed={2} rotationIntensity={1} floatIntensity={1}>
          <EidCube />
        </Float>

        {/* Floating Message */}
        <Text
          position={[0, -3, 0]}
          color="#ffd700"
          fontSize={0}
          maxWidth={200}
          lineHeight={1}
          textAlign="center"
        >
          Click the Cube for a Blessing!
        </Text>

        <OrbitControls enableZoom={false} />
      </Canvas>

      {/* Overlay Message for HCI Interaction */}
      <div style={{
        position: 'absolute',
        top: '10%',
        left: '50%',
        transform: 'translateX(-50%)',
        color: '#ffd700',
        fontFamily: 'serif',
        fontSize: '2rem',
        textAlign: 'center',
        pointerEvents: 'none',
        textShadow: '2px 2px 10px rgba(0,0,0,0.5)'
      }}>
        <p style={{ fontSize: '0.9rem' }}>May your days be filled with joy and peace.</p>
      </div>
    </div>
  )
}
